package com.grit.liferecorder.ui.tasks
import androidx.compose.foundation.ExperimentalFoundationApi; import androidx.compose.foundation.combinedClickable; import androidx.compose.foundation.layout.*; import androidx.compose.foundation.lazy.*; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.text.font.FontWeight; import androidx.compose.ui.unit.dp; import androidx.lifecycle.compose.collectAsStateWithLifecycle; import com.grit.liferecorder.data.local.entity.TaskEntity
@Composable fun TasksScreen(viewModel:TasksViewModel,padding:PaddingValues){ val state by viewModel.state.collectAsStateWithLifecycle(); var title by remember{ mutableStateOf("") }; LazyColumn(Modifier.padding(padding).fillMaxSize(),contentPadding=PaddingValues(16.dp),verticalArrangement=Arrangement.spacedBy(12.dp)){ item{ Text("Tasks",style=MaterialTheme.typography.headlineMedium); Text("Tap to review. Long press to complete.",color=MaterialTheme.colorScheme.onSurfaceVariant) }; item{ Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){ OutlinedTextField(title,{title=it},label={Text("New task title")},modifier=Modifier.weight(1f)); Button(onClick={viewModel.add(title); title=""}){Text("Add")} } }; item{ TaskFilters(state.filter,viewModel::setFilter) }; items(state.tasks,key={it.id}){ TaskCard(it,{},{viewModel.complete(it)},{viewModel.cancel(it)}) } } }
@Composable fun TaskFilters(selected:String,onSelect:(String)->Unit){ Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){ listOf("All","Open","Completed","Overdue").forEach{ FilterChip(selected=selected==it,onClick={onSelect(it)},label={Text(it)}) } } }
@OptIn(ExperimentalFoundationApi::class) @Composable fun TaskCard(task:TaskEntity,onClick:()->Unit,onLong:()->Unit,onCancel:()->Unit){ Card(Modifier.fillMaxWidth().combinedClickable(onClick=onClick,onLongClick=onLong)){ Column(Modifier.padding(16.dp),verticalArrangement=Arrangement.spacedBy(6.dp)){ Row(Modifier.fillMaxWidth(),horizontalArrangement=Arrangement.SpaceBetween){ Text(task.title,fontWeight=FontWeight.Bold); Text(task.priority) }; Text("Status: ${task.status} • Complete by: ${task.completeByDate ?: "No deadline"}",color=MaterialTheme.colorScheme.onSurfaceVariant); if(task.status=="Open") TextButton(onClick=onCancel){Text("Cancel task")} } } }
@Composable fun TaskList(tasks:List<TaskEntity>,onComplete:(TaskEntity)->Unit){ Column(verticalArrangement=Arrangement.spacedBy(8.dp)){ tasks.forEach{TaskCard(it,{},{onComplete(it)},{})} } }
@Composable fun TaskEditorScreen(){ Text("Task editor: title, description, category, project, complete-by, reminder, priority, save and delete.") }
